24	/********************************************************************
25	 * Estimate the number of blocks to be added to the whole device bitstream
26	 * This function will recursively walk through the module graph
27	 * from the specified top module and count the number of configurable children
28	 * which are the blocks that will be added to the bitstream manager
29	 *******************************************************************/
30	static size_t rec_estimate_device_bitstream_num_blocks(
31	  const ModuleManager& module_manager, const ModuleId& top_module) {
32	  size_t num_blocks = 0;
33	
34	  /* Those child modules which have no children are
35	   * actually configurable memory elements
36	   * We skip them in couting
37	   */
38	  if (0 == module_manager.num_configurable_children(
39	             top_module, ModuleManager::e_config_child_type::PHYSICAL)) {
40	    return 0;
41	  }
42	
43	  size_t num_configurable_children =
44	    module_manager
45	      .configurable_children(top_module,
46	                             ModuleManager::e_config_child_type::PHYSICAL)
47	      .size();
48	  for (size_t ichild = 0; ichild < num_configurable_children; ++ichild) {
49	    ModuleId child_module = module_manager.configurable_children(
50	      top_module, ModuleManager::e_config_child_type::PHYSICAL)[ichild];
51	    num_blocks +=
52	      rec_estimate_device_bitstream_num_blocks(module_manager, child_module);
53	  }
54	
55	  /* Add the number of blocks at current level */
56	  num_blocks++;
57	
58	  return num_blocks;
59	}
60	
61	/********************************************************************
62	 * Estimate the number of configuration bits to be added to the whole device
63	 *bitstream This function will recursively walk through the module graph from
64	 *the specified top module and count the number of leaf configurable children
65	 * which are the bits that will be added to the bitstream manager
66	 *******************************************************************/
67	static size_t rec_estimate_device_bitstream_num_bits(
68	  const ModuleManager& module_manager, const ModuleId& top_module,
69	  const ModuleId& parent_module, const ConfigProtocol& config_protocol) {
70	  size_t num_bits = 0;
71	
72	  /* If a child module has no configurable children, this is a leaf node
73	   * We can count it in. Otherwise, we should go recursively.
74	   */
75	  if (0 == module_manager.num_configurable_children(
76	             parent_module, ModuleManager::e_config_child_type::PHYSICAL)) {
77	    return 1;
78	  }
79	
80	  /* Two cases to walk through configurable children:
81	   * - For top-level module:
82	   *   Iterate over the multiple regions and visit each configuration child
83	   * under any region In each region, frame-based configuration protocol or
84	   * memory bank protocol will contain decoders. We should bypass them when
85	   * count the bitstream size
86	   * - For other modules:
87	   *   Iterate over the configurable children regardless of regions
88	   */
89	  if (parent_module == top_module) {
90	    for (const ConfigRegionId& config_region :
91	         module_manager.regions(parent_module)) {
92	      size_t curr_region_num_config_child =
93	        module_manager
94	          .region_configurable_children(parent_module, config_region)
95	          .size();
96	      size_t num_child_to_skip =
97	        estimate_num_configurable_children_to_skip_by_config_protocol(
98	          config_protocol, curr_region_num_config_child);
99	      curr_region_num_config_child -= num_child_to_skip;
100	
101	      /* Visit all the children in a recursively way */
102	      for (size_t ichild = 0; ichild < curr_region_num_config_child; ++ichild) {
103	        ModuleId child_module = module_manager.region_configurable_children(
104	          parent_module, config_region)[ichild];
105	        num_bits += rec_estimate_device_bitstream_num_bits(
106	          module_manager, top_module, child_module, config_protocol);
107	      }
108	    }
109	  } else {
110	    VTR_ASSERT_SAFE(parent_module != top_module);
111	
112	    size_t num_configurable_children =
113	      module_manager
114	        .configurable_children(parent_module,
115	                               ModuleManager::e_config_child_type::PHYSICAL)
116	        .size();
117	
118	    /* Frame-based configuration protocol will have 1 decoder
119	     * if there are more than 1 configurable children
120	     */
121	    if ((CONFIG_MEM_FRAME_BASED == config_protocol.type()) &&
122	        (2 <= num_configurable_children)) {
123	      num_configurable_children--;
124	    }
125	
126	    for (size_t ichild = 0; ichild < num_configurable_children; ++ichild) {
127	      ModuleId child_module = module_manager.configurable_children(
128	        parent_module, ModuleManager::e_config_child_type::PHYSICAL)[ichild];
129	      num_bits += rec_estimate_device_bitstream_num_bits(
130	        module_manager, top_module, child_module, config_protocol);
131	    }
132	  }
133	
134	  return num_bits;
135	}
