16	/********************************************************************
17	 * Identify if fast configuration is applicable base on the availability
18	 * of programming reset and programming set ports of the FPGA fabric
19	 *******************************************************************/
20	bool is_fast_configuration_applicable(
21	  const FabricGlobalPortInfo& global_ports) {
22	  /* Preparation: find all the reset/set ports for programming usage */
23	  std::vector<FabricGlobalPortId> global_prog_reset_ports =
24	    find_fabric_global_programming_reset_ports(global_ports);
25	  std::vector<FabricGlobalPortId> global_prog_set_ports =
26	    find_fabric_global_programming_set_ports(global_ports);
27	
28	  /* Identify if we can apply fast configuration */
29	  if (global_prog_set_ports.empty() && global_prog_reset_ports.empty()) {
30	    VTR_LOG_WARN(
31	      "None of global reset and set ports are defined for programming purpose. "
32	      "Fast configuration is not applicable\n");
33	    return false;
34	  }
35	
36	  return true;
37	}
38	
39	/********************************************************************
40	 * Decide if we should use reset or set signal to acheive fast configuration
41	 * - If only one type signal is specified, we use that type
42	 *   For example, only reset signal is defined, we will use reset
43	 * - If both are defined, pick the one that will bring bigger reduction
44	 *   i.e., larger number of configuration bits can be skipped
45	 *******************************************************************/
46	bool find_bit_value_to_skip_for_fast_configuration(
47	  const e_config_protocol_type& config_protocol_type,
48	  const FabricGlobalPortInfo& global_ports,
49	  const BitstreamManager& bitstream_manager,
50	  const FabricBitstream& fabric_bitstream) {
51	  /* Preparation: find all the reset/set ports for programming usage */
52	  std::vector<FabricGlobalPortId> global_prog_reset_ports =
53	    find_fabric_global_programming_reset_ports(global_ports);
54	  std::vector<FabricGlobalPortId> global_prog_set_ports =
55	    find_fabric_global_programming_set_ports(global_ports);
56	
57	  /* Early exit conditions */
58	  if (!global_prog_reset_ports.empty() && global_prog_set_ports.empty()) {
59	    return false;
60	  } else if (!global_prog_set_ports.empty() &&
61	             global_prog_reset_ports.empty()) {
62	    return true;
63	  }
64	
65	  /* If both types of ports are not defined, the fast configuration is not
66	   * applicable */
67	  VTR_ASSERT(!global_prog_set_ports.empty() &&
68	             !global_prog_reset_ports.empty());
69	  bool bit_value_to_skip = false;
70	
71	  VTR_LOG(
72	    "Both reset and set ports are defined for programming controls, selecting "
73	    "the best-fit one...\n");
74	
75	  size_t num_ones_to_skip = 0;
76	  size_t num_zeros_to_skip = 0;
77	
78	  /* Branch on the type of configuration protocol */
79	  switch (config_protocol_type) {
80	    case CONFIG_MEM_STANDALONE:
81	      break;
82	    case CONFIG_MEM_SCAN_CHAIN: {
83	      /* We can only skip the ones/zeros at the beginning of the bitstream */
84	      /* Count how many logic '1' bits we can skip */
85	      for (const FabricBitId& bit_id : fabric_bitstream.bits()) {
86	        if (false ==
87	            bitstream_manager.bit_value(fabric_bitstream.config_bit(bit_id))) {
88	          break;
89	        }
90	        VTR_ASSERT(true == bitstream_manager.bit_value(
91	                             fabric_bitstream.config_bit(bit_id)));
92	        num_ones_to_skip++;
93	      }
94	      /* Count how many logic '0' bits we can skip */
95	      for (const FabricBitId& bit_id : fabric_bitstream.bits()) {
96	        if (true ==
97	            bitstream_manager.bit_value(fabric_bitstream.config_bit(bit_id))) {
98	          break;
99	        }
100	        VTR_ASSERT(false == bitstream_manager.bit_value(
101	                              fabric_bitstream.config_bit(bit_id)));
102	        num_zeros_to_skip++;
103	      }
104	      break;
105	    }
106	    case CONFIG_MEM_QL_MEMORY_BANK:
107	    case CONFIG_MEM_MEMORY_BANK:
108	    case CONFIG_MEM_FRAME_BASED: {
109	      /* Count how many logic '1' and logic '0' bits we can skip */
110	      for (const FabricBitId& bit_id : fabric_bitstream.bits()) {
111	        if (false ==
112	            bitstream_manager.bit_value(fabric_bitstream.config_bit(bit_id))) {
113	          num_zeros_to_skip++;
114	        } else {
115	          VTR_ASSERT(true == bitstream_manager.bit_value(
116	                               fabric_bitstream.config_bit(bit_id)));
117	          num_ones_to_skip++;
118	        }
119	      }
120	      break;
121	    }
122	    default:
123	      VTR_LOGF_ERROR(__FILE__, __LINE__,
124	                     "Invalid configuration protocol type!\n");
125	      exit(1);
126	  }
127	
128	  VTR_LOG("Using reset will skip %g% (%lu/%lu) of configuration bitstream.\n",
129	          100. * (float)num_zeros_to_skip / (float)fabric_bitstream.num_bits(),
130	          num_zeros_to_skip, fabric_bitstream.num_bits());
131	
132	  VTR_LOG("Using set will skip %g% (%lu/%lu) of configuration bitstream.\n",
133	          100. * (float)num_ones_to_skip / (float)fabric_bitstream.num_bits(),
134	          num_ones_to_skip, fabric_bitstream.num_bits());
135	
136	  /* By default, we prefer to skip zeros (when the numbers are the same */
137	  if (num_ones_to_skip > num_zeros_to_skip) {
138	    VTR_LOG("Will use set signal in fast configuration\n");
139	    bit_value_to_skip = true;
140	  } else {
141	    VTR_LOG("Will use reset signal in fast configuration\n");
142	  }
143	
144	  return bit_value_to_skip;
145	}
