83	/********************************************************************
84	 * Generate bitstream for a primitive node and add it to bitstream manager
85	 *******************************************************************/
86	static void build_primitive_bitstream(
87	  BitstreamManager& bitstream_manager,
88	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
89	  const ConfigBlockId& parent_configurable_block,
90	  const ModuleManager& module_manager, const CircuitLibrary& circuit_lib,
91	  const VprDeviceAnnotation& device_annotation, const PhysicalPb& physical_pb,
92	  const PhysicalPbId& primitive_pb_id, t_pb_type* primitive_pb_type,
93	  const VprBitstreamAnnotation& bitstream_annotation,
94	  const bool& pcf_mode_specified, const bool& verbose) {
95	  /* Ensure a valid physical pritimive pb */
96	  if (nullptr == primitive_pb_type) {
97	    VTR_LOGF_ERROR(__FILE__, __LINE__, "Invalid primitive_pb_type!\n");
98	    exit(1);
99	  }
100	
101	  CircuitModelId primitive_model =
102	    device_annotation.pb_type_circuit_model(primitive_pb_type);
103	  VTR_ASSERT(CircuitModelId::INVALID() != primitive_model);
104	  VTR_ASSERT(
105	    (CIRCUIT_MODEL_IOPAD == circuit_lib.model_type(primitive_model)) ||
106	    (CIRCUIT_MODEL_HARDLOGIC == circuit_lib.model_type(primitive_model)) ||
107	    (CIRCUIT_MODEL_FF == circuit_lib.model_type(primitive_model)));
108	
109	  /* Find SRAM ports for mode-selection */
110	  std::vector<CircuitPortId> primitive_mode_select_ports =
111	    find_circuit_mode_select_sram_ports(circuit_lib, primitive_model);
112	
113	  /* We may have a port for mode select or not. */
114	  VTR_ASSERT((0 == primitive_mode_select_ports.size()) ||
115	             (1 == primitive_mode_select_ports.size()));
116	
117	  /* Generate bitstream for mode-select ports */
118	  if (0 == primitive_mode_select_ports.size()) {
119	    return; /* Nothing to do, return directly */
120	  }
121	
122	  std::vector<bool> mode_select_bitstream;
123	  if (true == physical_pb.valid_pb_id(primitive_pb_id)) {
124	    mode_select_bitstream = generate_mode_select_bitstream(
125	      physical_pb.mode_bits(primitive_pb_id),
126	      device_annotation.pb_type_mode_bits(primitive_pb_type));
127	    /* If the physical pb contains fixed mode-select bitstream, overload here */
128	    for (const auto& fix_bitstrm :
129	         physical_pb.fixed_mode_select_bitstreams(primitive_pb_id)) {
130	      std::string fixed_mode_select_bitstream = fix_bitstrm.content;
131	      size_t mode_bits_start_index = fix_bitstrm.offset;
132	      /* Ensure the length matches!!! */
133	      if (mode_select_bitstream.size() - mode_bits_start_index <
134	          fixed_mode_select_bitstream.size()) {
135	        VTR_LOG_ERROR(
136	          "Unmatched length of fixed mode_select_bitstream %s!Expected to be "
137	          "less than %ld bits\n",
138	          fixed_mode_select_bitstream.c_str(),
139	          mode_select_bitstream.size() - mode_bits_start_index);
140	        exit(1);
141	      }
142	      /* Overload the bitstream here */
143	      for (size_t bit_index = 0; bit_index < fixed_mode_select_bitstream.size();
144	           ++bit_index) {
145	        VTR_ASSERT('0' == fixed_mode_select_bitstream[bit_index] ||
146	                   '1' == fixed_mode_select_bitstream[bit_index]);
147	        mode_select_bitstream[bit_index + mode_bits_start_index] =
148	          ('1' == fixed_mode_select_bitstream[bit_index]);
149	      }
150	    }
